require_once __DIR__.'/functions.php';$raw=(string)($_GET['token']??'');if(!preg_match('/^[a-f0-9]{64}$/',$raw)){flash('El enlace es inválido.','error');redirect('/login.php');}$pdo=db();$stmt=$pdo->prepare('SELECT id,user_id FROM user_email_tokens WHERE token_hash=? AND used_at IS NULL AND expires_at>NOW()');$stmt->execute([hash('sha256',$raw)]);$token=$stmt->fetch();if(!$token){flash('El enlace es inválido o ya venció.','error');redirect('/login.php');}$pdo->beginTransaction();$pdo->prepare('UPDATE users SET email_verified_at=NOW() WHERE id=?')->execute([$token['user_id']]);$pdo->prepare('UPDATE user_email_tokens SET used_at=NOW() WHERE id=?')->execute([$token['id']]);$pdo->commit();flash('Correo administrativo verificado.');redirect(is_logged_in()?'/staff-profile.php':'/login.php');
